import{_ as i,c as a,o,ae as t}from"./chunks/framework.Bw7rlmih.js";const u=JSON.parse('{"title":"Control Plane Feature Specs","description":"","frontmatter":{},"headers":[],"relativePath":"control-plane/index.md","filePath":"control-plane/index.md"}'),l={name:"control-plane/index.md"};function r(n,e,s,c,d,p){return o(),a("div",null,e[0]||(e[0]=[t('<h1 id="control-plane-feature-specs" tabindex="-1">Control Plane Feature Specs <a class="header-anchor" href="#control-plane-feature-specs" aria-label="Permalink to &quot;Control Plane Feature Specs&quot;">​</a></h1><p>This folder contains implementation-level specifications for the Konfigo control plane roadmap items selected for the next major evolution:</p><ul><li><ol start="4"><li>Drift detection</li></ol></li><li><ol start="13"><li>GitOps and direct API mode</li></ol></li><li><ol start="14"><li>Terraform provider and Kubernetes operator</li></ol></li><li><ol start="15"><li>Events and webhooks</li></ol></li><li><ol start="19"><li>Query and search language</li></ol></li><li><ol start="20"><li>Disaster recovery (without operational drill workflows)</li></ol></li></ul><h2 id="why-this-set" tabindex="-1">Why This Set <a class="header-anchor" href="#why-this-set" aria-label="Permalink to &quot;Why This Set&quot;">​</a></h2><p>These features make Konfigo a full control plane instead of only a local config processor:</p><ul><li><strong>Operate centrally</strong> from any environment.</li><li><strong>Enforce safety</strong> through immutable bundles, policy gates, and approvals.</li><li><strong>Integrate deeply</strong> with CI/CD, Infrastructure-as-Code, and Kubernetes.</li><li><strong>Observe and recover</strong> with first-class events, drift visibility, and backup/restore.</li></ul><h2 id="shared-architecture-decisions" tabindex="-1">Shared Architecture Decisions <a class="header-anchor" href="#shared-architecture-decisions" aria-label="Permalink to &quot;Shared Architecture Decisions&quot;">​</a></h2><p>All specs in this folder assume the same baseline.</p><h3 id="_1-logical-organization-by-scope-prefix" tabindex="-1">1. Logical Organization by Scope Prefix <a class="header-anchor" href="#_1-logical-organization-by-scope-prefix" aria-label="Permalink to &quot;1. Logical Organization by Scope Prefix&quot;">​</a></h3><p>No hard multi-tenant namespace model is required for this phase.</p><ul><li>Use a canonical <code>scope</code> string like <code>team/app/env/service</code>.</li><li>Apply this same <code>scope</code> in all objects, access checks, storage keys, and events.</li><li>Store remote values by provider prefix, for example: <ul><li>Vault: <code>kv/konfigo/&lt;scope&gt;/...</code></li><li>S3: <code>s3://konfigo-config/&lt;scope&gt;/...</code></li></ul></li></ul><h3 id="_2-auth-and-identity" tabindex="-1">2. Auth and Identity <a class="header-anchor" href="#_2-auth-and-identity" aria-label="Permalink to &quot;2. Auth and Identity&quot;">​</a></h3><p>Username/password is not the primary path.</p><ul><li>Humans: OIDC SSO (browser or device code).</li><li>CI/CD: workload identity federation (OIDC token exchange).</li><li>Services: short-lived scoped tokens.</li><li>Authorization: RBAC/ABAC on scope prefixes.</li></ul><h3 id="_3-immutable-versioned-objects" tabindex="-1">3. Immutable Versioned Objects <a class="header-anchor" href="#_3-immutable-versioned-objects" aria-label="Permalink to &quot;3. Immutable Versioned Objects&quot;">​</a></h3><p>Core objects are immutable once published:</p><ul><li><code>Schema@version</code></li><li><code>Template@version</code></li><li><code>Values@version</code></li><li><code>Bundle@version</code> (the deployable resolved unit)</li></ul><p>Promotion flows move references, not mutable content.</p><h3 id="_4-event-first-control-plane" tabindex="-1">4. Event-First Control Plane <a class="header-anchor" href="#_4-event-first-control-plane" aria-label="Permalink to &quot;4. Event-First Control Plane&quot;">​</a></h3><p>Every important state transition emits events:</p><ul><li>publish, promote, drift detected/resolved, rollback, restore</li></ul><p>This is required by GitOps reconcile loops, operator behavior, notifications, and audit.</p><h2 id="spec-files" tabindex="-1">Spec Files <a class="header-anchor" href="#spec-files" aria-label="Permalink to &quot;Spec Files&quot;">​</a></h2><ul><li><a href="./04-drift-detection.html">04-drift-detection.md</a></li><li><a href="./13-gitops-and-api-mode.html">13-gitops-and-api-mode.md</a></li><li><a href="./14-terraform-provider-and-k8s-operator.html">14-terraform-provider-and-k8s-operator.md</a></li><li><a href="./15-events-and-webhooks.html">15-events-and-webhooks.md</a></li><li><a href="./19-query-and-search-language.html">19-query-and-search-language.md</a></li><li><a href="./20-disaster-recovery.html">20-disaster-recovery.md</a></li></ul><h2 id="suggested-delivery-sequence" tabindex="-1">Suggested Delivery Sequence <a class="header-anchor" href="#suggested-delivery-sequence" aria-label="Permalink to &quot;Suggested Delivery Sequence&quot;">​</a></h2><ol><li>Events and webhooks (<code>15</code>)</li><li>Query and search language (<code>19</code>)</li><li>Drift detection (<code>4</code>)</li><li>GitOps and API dual mode (<code>13</code>)</li><li>Terraform provider and Kubernetes operator (<code>14</code>)</li><li>Disaster recovery (<code>20</code>)</li></ol><p>This order keeps foundational dependencies in front and reduces rework.</p><h2 id="atomic-development-specs" tabindex="-1">Atomic Development Specs <a class="header-anchor" href="#atomic-development-specs" aria-label="Permalink to &quot;Atomic Development Specs&quot;">​</a></h2><p>For implementation planning and ticketing, use the atomic set:</p><ul><li><a href="./atomic/README.html">atomic/README.md</a></li></ul><p>The atomic specs split each concern into contained, testable units with:</p><ul><li>strict purpose and boundaries</li><li>explicit interface contracts</li><li>invariants and failure modes</li><li>concrete acceptance criteria</li></ul>',32)]))}const m=i(l,[["render",r]]);export{u as __pageData,m as default};
